mapper.select:
SELECT p.id AS planId, p.date AS planDate, p.description AS planDesc, w.id AS workerId, w.name AS workerName, w.tel AS workerTel, ds.name AS deptSubName, d.name AS deptName, gu.user_name AS userName, gu.contact_phone AS userPhone, gu.address AS userAddress, gu.building_info AS buildingInfo, i.id AS inspectionId, i.inspect_date AS inspectDate, i.has_danger AS hasDanger, i.inspect_desc AS inspectDesc, i.inspect_photo AS inspectPhoto, i.inspect_result AS inspectResult FROM gas_worker_plan p LEFT JOIN gas_worker w ON p.worker_id = w.id LEFT JOIN medical_dept_sub ds ON p.dept_sub_id = ds.id LEFT JOIN medical_dept d ON ds.dept_id = d.id LEFT JOIN gas_user gu ON p.user_id = gu.id LEFT JOIN gas_worker_inspection i ON p.id = i.worker_plan_id WHERE 1=1
AND w.name LIKE CONCAT("%", #{workerName}, "%")
AND d.id = #{deptId}
AND p.date >= #{startDate}
AND p.date <= #{endDate}
AND i.has_danger = #{hasDanger}
AND i.inspect_result = #{inspectResult}
ORDER BY p.date DESC, p.id DESC
